  { bg: 'bg-blue-50', darkBg: 'dark:bg-blue-900/40', progress: 'bg-blue-500' },
  { bg: 'bg-green-50', darkBg: 'dark:bg-green-900/40', progress: 'bg-green-500' },
  { bg: 'bg-indigo-50', darkBg: 'dark:bg-indigo-900/40', progress: 'bg-indigo-500' },
